<svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="26" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">ガンマ・エクスポージャー — 方向ではなく圧力を測る指標</text>
  <rect x="20" y="45" width="310" height="190" rx="8" fill="#22c55e" opacity="0.09" stroke="#22c55e" stroke-opacity="0.4"/>
